import{_ as e,o as a,c as o,ag as l}from"./chunks/framework.ZAJMUlQ0.js";const _=JSON.parse('{"title":"4.29日报(ai)","description":"","frontmatter":{"title":"4.29日报(ai)","date":"2026-06-02T00:00:00.000Z","tags":["html","table","rowspan","colspan","web-development"],"summary":"本文介绍了HTML中的基础标签，包括段落标签、不换行标签、超链接标签和图片标签。重点讲解了表格标签的使用，特别是rowspan（行合并）和colspan（列合并）属性的用法。通过示例说明如何在td上应用这两个属性来实现单元格的合并（合并2行3列，共6个单元格）。同时，文章还明确了tr代表表格的行、td代表表格的列，为初学者提供了清晰的HTML表格基础知识点。"},"headers":[],"relativePath":"posts/2026-06-02-0429day.md","filePath":"posts/2026-06-02-0429day.md"}'),d={name:"posts/2026-06-02-0429day.md"};function c(r,t,s,i,p,n){return a(),o("div",null,[...t[0]||(t[0]=[l('<h3 id="_4-29" tabindex="-1">4.29 <a class="header-anchor" href="#_4-29" aria-label="Permalink to &quot;4.29&quot;">​</a></h3><h3 id="html基础标签" tabindex="-1">HTML基础标签 <a class="header-anchor" href="#html基础标签" aria-label="Permalink to &quot;HTML基础标签&quot;">​</a></h3><ul><li><code>&lt;p&gt;&lt;/p&gt;</code> 段落，自动换行</li><li><code>&lt;span&gt;&lt;/span&gt;</code> 不换行</li><li><code>&lt;a href=&quot;&quot;&gt;&lt;/a&gt;</code> 超链接</li><li><code>&lt;img src=&quot;&quot; /&gt;</code> 图片</li></ul><h4 id="table-标签的使用" tabindex="-1"><code>&lt;table&gt;</code> 标签的使用 <a class="header-anchor" href="#table-标签的使用" aria-label="Permalink to &quot;`&lt;table&gt;` 标签的使用&quot;">​</a></h4><p>主要：</p><p><code>rowspan</code>（行合并）与 <code>colspan</code>（列合并）的用法</p><p>一般都写在 <code>&lt;td&gt;</code> 上。例如：<code>&lt;td rowspan=&quot;2&quot; colspan=&quot;3&quot;&gt;</code> 从该单元格开始合并 2 行 3 列，共计 6 个单元格。</p><ul><li><p><code>rowspan</code>：从该单元格开始合并几行，默认一列</p></li><li><p><code>colspan</code>：从该单元格开始合并几列，默认一行</p></li><li><p><code>&lt;tr&gt;</code> 代表表格的行</p></li><li><p><code>&lt;td&gt;</code> 代表表格的列</p></li></ul>',8)])])}const h=e(d,[["render",c]]);export{_ as __pageData,h as default};
